import React from "react";

function Merch(props) {
  const { name, price, description } = props.merchandise;

  return (
    <div>
      <h2>{name}</h2>
      <p>Price: ${Number(price || 0).toFixed(2)}</p>
      <p>Description: {description}</p>
      <button>Edit</button>
      <button>Delete</button>
    </div>
  );
 }

export default Merch;
